import{_ as e,o as t,c as r,ag as d}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"AIUI SDK 基础能力","description":"","frontmatter":{"title":"AIUI SDK 基础能力"},"headers":[],"relativePath":"sdk-dev/features/index.md","filePath":"sdk-dev/features/index.md","lastUpdated":null}'),s={name:"sdk-dev/features/index.md"};function i(o,a,h,l,n,p){return t(),r("div",null,[...a[0]||(a[0]=[d('<p>✧</p><h2 id="aiui-sdk基础能力" tabindex="-1">AIUI SDK基础能力 <a class="header-anchor" href="#aiui-sdk基础能力" aria-label="Permalink to &quot;AIUI SDK基础能力&quot;">​</a></h2><p>探索SDK提供的核心功能与特色能力</p><p>▼</p><h3 id="流式识别" tabindex="-1">流式识别 <a class="header-anchor" href="#流式识别" aria-label="Permalink to &quot;流式识别&quot;">​</a></h3><p>实时处理语音流并转换为文本，支持边说边识别的连续交互模式。</p><p><a href="/sdk-dev/features/streaming-asr.html">查看详情</a></p><h3 id="离线识别" tabindex="-1">离线识别 <a class="header-anchor" href="#离线识别" aria-label="Permalink to &quot;离线识别&quot;">​</a></h3><p>无需网络连接即可进行语音识别，保障无网络环境下的基本功能使用。</p><p><a href="/sdk-dev/features/offline-asr.html">查看详情</a></p><h3 id="语音唤醒" tabindex="-1">语音唤醒 <a class="header-anchor" href="#语音唤醒" aria-label="Permalink to &quot;语音唤醒&quot;">​</a></h3><p>通过特定唤醒词激活设备，支持自定义唤醒词及灵敏度调节。</p><p><a href="/sdk-dev/features/wakeword.html">查看详情</a></p><h3 id="语音合成" tabindex="-1">语音合成 <a class="header-anchor" href="#语音合成" aria-label="Permalink to &quot;语音合成&quot;">​</a></h3><p>将文本转换为自然流畅的语音，支持多种音色、语速和音量调节。</p><p><a href="/sdk-dev/features/tts.html">查看详情</a></p><h3 id="用户个性化" tabindex="-1">用户个性化 <a class="header-anchor" href="#用户个性化" aria-label="Permalink to &quot;用户个性化&quot;">​</a></h3><p>根据用户习惯和历史数据提供个性化交互体验，提升识别准确率。</p><p><a href="/sdk-dev/features/personalization.html">查看详情</a></p><h3 id="自定义参数" tabindex="-1">自定义参数 <a class="header-anchor" href="#自定义参数" aria-label="Permalink to &quot;自定义参数&quot;">​</a></h3><p>支持通过参数配置定制SDK行为，满足不同场景下的个性化需求。</p><p><a href="/sdk-dev/features/custom-params.html">查看详情</a></p>',22)])])}const c=e(s,[["render",i]]);export{u as __pageData,c as default};
